(()=>{"use strict";window.onload=function(){setInterval(e,1e3),t()};const e=()=>{const e=document.querySelector(".clock"),t=new Date,r=String(t.getHours()).padStart(2,"0"),n=String(t.getMinutes()).padStart(2,"0"),a=String(t.getSeconds()).padStart(2,"0");e.innerText=`${r}:${n}:${a}`},t=()=>{const e=document.querySelector(".calendar"),t=new Date,r=String(t.getFullYear()),n=t.getMonth(),a=String(t.getDate()),u=t.getDay();e.innerText=`${["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"][u]}, ${["January","February","March","April","May","June","July","August","September","October","November","December"][n]} ${a}, ${r}`}})();